'use client';

import React, { useState } from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';
import { MediaUpload } from '@/components/ui/MediaUpload';

const inputCls = 'w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm';
const textareaCls = inputCls + ' resize-none';

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">{label}</label>
      {children}
    </div>
  );
}

function Collapsible({ title, children, defaultOpen = false }: { title: string; children: React.ReactNode; defaultOpen?: boolean }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="border border-gray-200 dark:border-gray-600 rounded-lg overflow-hidden">
      <button type="button" onClick={() => setOpen(o => !o)}
        className="w-full flex items-center justify-between px-3 py-2.5 bg-gray-50 dark:bg-gray-700 hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors text-left">
        <span className="text-sm font-medium text-gray-800 dark:text-white">{title}</span>
        <span className={`text-gray-400 text-xs transition-transform ${open ? 'rotate-90' : ''}`}>▶</span>
      </button>
      {open && <div className="p-3 space-y-3 bg-white dark:bg-gray-800">{children}</div>}
    </div>
  );
}

function ColorField({ label, value, onChange }: { label: string; value: string; onChange: (v: string) => void }) {
  return (
    <Field label={label}>
      <div className="flex gap-2">
        <input type="color" value={value} onChange={e => onChange(e.target.value)}
          className="w-10 h-9 rounded border border-gray-300 dark:border-gray-600 cursor-pointer p-0.5 bg-white dark:bg-gray-700" />
        <input className={inputCls} value={value} onChange={e => onChange(e.target.value)} />
      </div>
    </Field>
  );
}

function MediaField({ label, src, objectFit, onSrcChange, onFitChange }: {
  label: string; src: string; objectFit: string;
  onSrcChange: (v: string) => void; onFitChange: (v: string) => void;
}) {
  return (
    <Collapsible title={label}>
      <p className="text-xs text-gray-500 dark:text-gray-400">Upload a real screenshot or video from your system to replace the default mock.</p>
      <MediaUpload
        src={src} alt={label} width={280} height={200}
        onMediaChange={onSrcChange}
        objectFit={objectFit as any}
        onObjectFitChange={onFitChange}
        showObjectFitControls showUploadButton
        uploadButtonText="Upload Screenshot / Video"
        acceptedTypes="image/*,video/*"
      />
    </Collapsible>
  );
}

/* ─── Reports Hero Panel ─── */
export function ReportsHeroPanelPanel({ section, onUpdate }: { section: SectionConfig; onUpdate: (u: Partial<SectionConfig>) => void }) {
  const d = section.data as any;
  const u = (p: any) => onUpdate({ data: { ...d, ...p } });
  return (
    <div className="space-y-4">
      <Collapsible title="Header" defaultOpen>
        <Field label="Badge"><input className={inputCls} value={d.badge ?? ''} onChange={e => u({ badge: e.target.value })} /></Field>
        <Field label="Title"><input className={inputCls} value={d.title ?? ''} onChange={e => u({ title: e.target.value })} /></Field>
        <Field label="Title Gradient"><input className={inputCls} value={d.titleGradient ?? ''} onChange={e => u({ titleGradient: e.target.value })} /></Field>
        <Field label="Subtitle"><textarea className={textareaCls} rows={2} value={d.subtitle ?? ''} onChange={e => u({ subtitle: e.target.value })} /></Field>
      </Collapsible>
      <Collapsible title="Buttons">
        <Field label="Primary Button Text"><input className={inputCls} value={d.primaryButtonText ?? ''} onChange={e => u({ primaryButtonText: e.target.value })} /></Field>
        <Field label="Primary Button Href"><input className={inputCls} value={d.primaryButtonHref ?? ''} onChange={e => u({ primaryButtonHref: e.target.value })} /></Field>
        <Field label="Secondary Button Text"><input className={inputCls} value={d.secondaryButtonText ?? ''} onChange={e => u({ secondaryButtonText: e.target.value })} /></Field>
        <Field label="Secondary Button Href"><input className={inputCls} value={d.secondaryButtonHref ?? ''} onChange={e => u({ secondaryButtonHref: e.target.value })} /></Field>
      </Collapsible>
      <MediaField label="Hero Media Frame (replaces default dashboard)"
        src={d.mediaUrl ?? ''} objectFit={d.mediaObjectFit ?? 'contain'}
        onSrcChange={v => u({ mediaUrl: v, mediaType: v ? (v.includes('.mp4') || v.includes('.webm') ? 'video' : 'image') : 'default' })}
        onFitChange={v => u({ mediaObjectFit: v })}
      />
      <Collapsible title="Accent Colors">
        <ColorField label="Accent 1" value={d.accentColor ?? '#6366f1'} onChange={v => u({ accentColor: v })} />
        <ColorField label="Accent 2" value={d.accentColor2 ?? '#818cf8'} onChange={v => u({ accentColor2: v })} />
        <ColorField label="Cyan" value={d.cyanColor ?? '#06b6d4'} onChange={v => u({ cyanColor: v })} />
      </Collapsible>
    </div>
  );
}

/* ─── Reports What You Can Build Panel ─── */
export function ReportsWhatYouCanBuildPanel({ section, onUpdate }: { section: SectionConfig; onUpdate: (u: Partial<SectionConfig>) => void }) {
  const d = section.data as any;
  const u = (p: any) => onUpdate({ data: { ...d, ...p } });
  const features: any[] = d.features ?? [];
  const updateFeature = (i: number, field: string, val: string) => {
    const next = features.map((f, idx) => idx === i ? { ...f, [field]: val } : f);
    u({ features: next });
  };
  return (
    <div className="space-y-4">
      <Collapsible title="Header" defaultOpen>
        <Field label="Eyebrow"><input className={inputCls} value={d.eyebrow ?? ''} onChange={e => u({ eyebrow: e.target.value })} /></Field>
        <Field label="Title"><input className={inputCls} value={d.title ?? ''} onChange={e => u({ title: e.target.value })} /></Field>
        <Field label="Title Gradient"><input className={inputCls} value={d.titleGradient ?? ''} onChange={e => u({ titleGradient: e.target.value })} /></Field>
        <Field label="Description"><textarea className={textareaCls} rows={2} value={d.description ?? ''} onChange={e => u({ description: e.target.value })} /></Field>
      </Collapsible>
      <Collapsible title={`Feature Cards (${features.length})`}>
        {features.map((f: any, i: number) => (
          <div key={i} className="border border-gray-200 dark:border-gray-600 rounded p-2 space-y-1.5">
            <div className="flex gap-2">
              <input className={inputCls} style={{ maxWidth: 50 }} value={f.icon ?? ''} onChange={e => updateFeature(i, 'icon', e.target.value)} placeholder="Icon" />
              <input className={inputCls} value={f.title ?? ''} onChange={e => updateFeature(i, 'title', e.target.value)} placeholder="Title" />
            </div>
            <textarea className={textareaCls} rows={2} value={f.description ?? ''} onChange={e => updateFeature(i, 'description', e.target.value)} placeholder="Description" />
          </div>
        ))}
      </Collapsible>
    </div>
  );
}

